CREATE OR REPLACE FUNCTION fn_update_amp_public_data_last_updated()
RETURNS TRIGGER AS $$
BEGIN
    IF TG_OP = 'INSERT'
    THEN
        NEW.amp_public_data_last_updated = NOW();
    ELSIF TG_OP = 'UPDATE' THEN
        IF (NEW.court_centre_id IS DISTINCT FROM OLD.court_centre_id OR
            NEW.type_id IS DISTINCT FROM OLD.type_id OR
            NEW.allocated IS DISTINCT FROM OLD.allocated OR
            NEW.start_date IS DISTINCT FROM OLD.start_date OR
            NEW.end_date IS DISTINCT FROM OLD.end_date OR
            NEW.estimated_minutes IS DISTINCT FROM OLD.estimated_minutes OR
            NEW.week_commencing_start_date IS DISTINCT FROM OLD.week_commencing_start_date OR
            NEW.week_commencing_end_date IS DISTINCT FROM OLD.week_commencing_end_date)
        THEN
            NEW.amp_public_data_last_updated = NOW();
        END IF;
    END IF;
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;
